import{_ as r,o as e,c as a,a2 as o}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"💡 光通訊追蹤日報 — 2026年6月3日（週三）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-06-03.md","filePath":"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-06-03.md"}'),d={name:"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_2026-06-03.md"};function i(n,t,l,s,h,p){return e(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="💡-光通訊追蹤日報-—-2026年6月3日-週三" tabindex="-1">💡 光通訊追蹤日報 — 2026年6月3日（週三） <a class="header-anchor" href="#💡-光通訊追蹤日報-—-2026年6月3日-週三" aria-label="Permalink to &quot;💡 光通訊追蹤日報 — 2026年6月3日（週三）&quot;">​</a></h1><blockquote><p><strong>查詢時間</strong>：TST 05:00 (2026-06-02 21:00 UTC) <strong>昨日敘事延續</strong>：NVIDIA Computex RTX Spark + Vera Rubin + $40 億光子投資 + Anthropic IPO + COMPUTEX 6/2 開幕 + 光通訊族群強勢</p></blockquote><hr><h2 id="🔴-即時指標-每日掃描" tabindex="-1">🔴 即時指標（每日掃描） <a class="header-anchor" href="#🔴-即時指標-每日掃描" aria-label="Permalink to &quot;🔴 即時指標（每日掃描）&quot;">​</a></h2><h3 id="指標1️⃣-輝達-nvidia-—-🟢-computex-持續催化-rtx-spark-量產討論-ai-基礎設施深化" tabindex="-1">指標1️⃣ 輝達 NVIDIA — 🟢 Computex 持續催化：RTX Spark 量產討論 + AI 基礎設施深化 <a class="header-anchor" href="#指標1️⃣-輝達-nvidia-—-🟢-computex-持續催化-rtx-spark-量產討論-ai-基礎設施深化" aria-label="Permalink to &quot;指標1️⃣ 輝達 NVIDIA — 🟢 Computex 持續催化：RTX Spark 量產討論 + AI 基礎設施深化&quot;">​</a></h3><p><strong>6/3 最新動態</strong>：</p><ul><li><strong>GTC Taipei 持續進行</strong>（6/2-5），今日有多場技術論壇： <ul><li>機器人、工業 AI、模擬、半導體工作流程</li><li>CPO 技術深度研討</li></ul></li><li><strong>RTX Spark</strong>：與微軟合作的 Windows on Arm PC 晶片，黃仁勳稱「電腦的重新發明」</li><li><strong>Vera Rubin 架構</strong>：Vera CPU + Rubin GPU，10 年 4,000 萬倍算力提升</li><li><strong>NVIDIA 光子投資 $40 億</strong>：Coherent + Lumentum 各 $20 億</li><li><strong>Spectrum-X Ethernet Photonics</strong>：409.6 Tb/s，<strong>2026 下半年上市</strong></li><li><strong>NVIDIA 台灣投資</strong>：每年 ~$1,500 億，2030 前建立台灣總部</li><li><strong>NVDA 股價</strong>：$211.14（6/1 收盤，-1.45%），6/2 盤前 +2.1%</li></ul><p><strong>評估</strong>：COMPUTEX 2026 本週為最大催化劑，NVIDIA 全方位佈局 AI 基礎設施 + CPO，台灣供應鏈直接受惠。</p><p>📎 來源：<a href="https://www.nvidia.com/en-tw/gtc/taipei/computex/" target="_blank" rel="noreferrer">NVIDIA</a>、<a href="https://www.pcmag.com/news/live-from-computex-2026-were-in-taipei-bringing-you-every-big-pc-reveal" target="_blank" rel="noreferrer">PCMag</a>、<a href="https://siliconangle.com/2026/06/01/nvidia-ramps-production-vera-rubin-foundation-next-generation-ai-factories/" target="_blank" rel="noreferrer">SiliconAngle</a>、<a href="https://forums.developer.nvidia.com/t/a-community-guide-to-nvidia-gtc-taipei-at-computex-2026/370571" target="_blank" rel="noreferrer">NVIDIA Forums</a>（TST 05:00）</p><hr><h3 id="指標2️⃣-博通-broadcom-—-🟡-computex-展示-edge-ai-cpo-路線圖-盤後財報成焦點" tabindex="-1">指標2️⃣ 博通 Broadcom — 🟡 COMPUTEX 展示 Edge AI + CPO 路線圖，盤後財報成焦點 <a class="header-anchor" href="#指標2️⃣-博通-broadcom-—-🟡-computex-展示-edge-ai-cpo-路線圖-盤後財報成焦點" aria-label="Permalink to &quot;指標2️⃣ 博通 Broadcom — 🟡 COMPUTEX 展示 Edge AI + CPO 路線圖，盤後財報成焦點&quot;">​</a></h3><p><strong>6/3 最新動態</strong>：</p><ul><li><strong>COMPUTEX 展示</strong>： <ul><li>50G PON Gateway SoC（整合 NPU）</li><li>Wi-Fi 8 全系列產品</li><li>與 Samsung 合作 5G + Wi-Fi 8 FWA 平台</li><li>Broadband Edge AI 產品組合</li></ul></li><li><strong>CPO 路線圖</strong>：交換器 ASIC 明確列出 CPO 版本</li><li><strong>合作夥伴</strong>： <ul><li>Alphabet：簽至 2031（客製化 AI 晶片）</li><li>Anthropic：2027 起取得 Google AI 算力</li><li>Meta：AI 加速器共同開發</li></ul></li><li><strong>Q2 FY2026 財報</strong>：6/3 盤後公布（TST 6/4 05:00） <ul><li>AI 收入預估：$107 億（+140% YoY）</li><li>AI Networking 佔 AI 收入 40%</li><li>管理層預測 FY2027 AI 晶片收入超 $1,000 億</li></ul></li></ul><p><strong>評估</strong>：Broadcom 盤後財報是本週最大催化劑之一，AI 收入能否超預期將決定光通訊族群短線走勢。</p><p>📎 來源：<a href="https://www.broadcom.com/" target="_blank" rel="noreferrer">Broadcom IR</a>、<a href="https://futurumgroup.com/insights/broadcom-lays-the-pipeline-for-the-intelligent-edge-with-50g-pon-and-wi-fi-8-at-computex-2026/" target="_blank" rel="noreferrer">FuturumGroup</a>、<a href="https://seekingalpha.com/news/4599887-broadcom-q2-2026-earnings-preview" target="_blank" rel="noreferrer">SeekingAlpha</a>（TST 05:00）</p><hr><h3 id="指標3️⃣-台積電-tsmc-—-🟢-coupe-穩定-computex-核心供應-市值全球第五" tabindex="-1">指標3️⃣ 台積電 TSMC — 🟢 COUPE 穩定 + COMPUTEX 核心供應 + 市值全球第五 <a class="header-anchor" href="#指標3️⃣-台積電-tsmc-—-🟢-coupe-穩定-computex-核心供應-市值全球第五" aria-label="Permalink to &quot;指標3️⃣ 台積電 TSMC — 🟢 COUPE 穩定 + COMPUTEX 核心供應 + 市值全球第五&quot;">​</a></h3><p><strong>6/3 最新動態</strong>：</p><ul><li><strong>COUPE 技術</strong>：小批量產階段，與 NVIDIA 合作光子整合</li><li><strong>CoWoS 產能</strong>：持續擴張以滿足 AI 晶片需求</li><li><strong>台積電（2330）</strong>：6/2 收盤 +1.06%，貢獻 TAIEX 約 200 點</li><li><strong>盤後鉅額交易</strong>：5/29 出現 2,442 元新高價</li><li><strong>魏哲家</strong>：員工分紅增幅至少不低於去年（30%），鼓勵員工買股</li><li><strong>台灣市值</strong>：已躍升全球第五大，81.44% 集中在科技產業</li><li><strong>大摩 COMPUTEX 報告</strong>：台積電為核心供應鏈，目標價維持</li></ul><p><strong>評估</strong>：台積電先進封裝是 CPO 量產的關鍵基礎設施，COUPE 進展穩定。</p><p>📎 來源：<a href="https://news.cnyes.com/news/id/6471653" target="_blank" rel="noreferrer">鉅亨網</a>、<a href="https://www.cna.com.tw/news/afe/202605280356.aspx" target="_blank" rel="noreferrer">CNA</a>、<a href="https://focustaiwan.tw/business/202606020020" target="_blank" rel="noreferrer">FocusTaiwan</a>（TST 05:00）</p><hr><h3 id="指標4️⃣-csp-資本支出-—-🟢-ai-capex-持續擴張-anthropic-ipo-softbank-14" tabindex="-1">指標4️⃣ CSP 資本支出 — 🟢 AI capex 持續擴張：Anthropic IPO + SoftBank +14% <a class="header-anchor" href="#指標4️⃣-csp-資本支出-—-🟢-ai-capex-持續擴張-anthropic-ipo-softbank-14" aria-label="Permalink to &quot;指標4️⃣ CSP 資本支出 — 🟢 AI capex 持續擴張：Anthropic IPO + SoftBank +14%&quot;">​</a></h3><p><strong>6/3 最新動態</strong>：</p><ul><li><strong>Anthropic 秘密提交 IPO</strong>：融資 $650 億，估值 $9,650 億</li><li><strong>SoftBank +14%</strong>（6/1 東京）→ AI 基礎設施投資持續</li><li><strong>南韓 Kospi +109% YTD</strong>：AI 晶片股主導</li><li>** Fundstrat Tom Lee**：「2026 年後可能看到我們一生中最大的股市漲幅」</li><li><strong>IDTechEx 預測</strong>：CPO 市場 2036 年超 $200 億，CAGR 37%（2026-2036）</li><li><strong>光纖供應短缺</strong>：全球光纖市場面臨嚴重供應短缺，預計持續至 2027，AI 數據中心 + 國防需求驅動</li><li><strong>台灣受惠</strong>：美廠 increasingly outsourcing to Southeast Asia → 台灣廠商（具東南亞產能）受惠</li></ul><p><strong>評估</strong>：AI capex 持續擴張 + 光纖供應短缺 → 光通訊族群基本面強勁。</p><p>📎 來源：<a href="https://www.theguardian.com/technology/2026/jun/01/anthropic-ai-ipo" target="_blank" rel="noreferrer">Guardian</a>、<a href="https://blogs.sw.siemens.com/semiconductor-packaging/2026/02/05/five-key-trends-of-co-packaged-optics-cpo-in-2026/" target="_blank" rel="noreferrer">Siemens Blog</a>、<a href="https://www.gl-fibercable.com/newsdetail/fiber-optic-market-outlook-2026:-why-prices-are-surging-and-when-to-buyyi.html" target="_blank" rel="noreferrer">GL-FiberCable</a>（TST 05:00）</p><hr><h2 id="🟡-台灣光通訊供應鏈" tabindex="-1">🟡 台灣光通訊供應鏈 <a class="header-anchor" href="#🟡-台灣光通訊供應鏈" aria-label="Permalink to &quot;🟡 台灣光通訊供應鏈&quot;">​</a></h2><table tabindex="0"><thead><tr><th>公司</th><th>代號</th><th>6/3 動態</th><th>評估</th></tr></thead><tbody><tr><td>聯亞</td><td>3081</td><td>無個股特定新聞</td><td>本日無個股更新</td></tr><tr><td>光聖</td><td>6442</td><td>無個股特定新聞</td><td>本日無個股更新</td></tr><tr><td>上詮</td><td>3363</td><td>無個股特定新聞</td><td>本日無個股更新</td></tr><tr><td>智邦</td><td>2345</td><td>無個股特定新聞</td><td>本日無個股更新</td></tr><tr><td>波若威</td><td>3163</td><td>COMPUTEX 催動，延續強勢</td><td>延續強勢</td></tr><tr><td>前鼎</td><td>—</td><td>COMPUTEX 催動，延續強勢</td><td>延續強勢</td></tr><tr><td>FICER Technology</td><td>—</td><td>COMPUTEX 展示高密度光纖解決方案</td><td>800G/400G + BiDi 模組</td></tr><tr><td>AuthenX</td><td>—</td><td>COMPUTEX 展示可拆卸 2D FAU 技術</td><td>CPO 封裝瓶頸解決方案</td></tr></tbody></table><p><strong>5/25-6/2 漲停族羣回顧</strong>：波若威、光聖、聯亞、前鼎 4 檔漲停，受 NVIDIA 光子投資 + COMPUTEX 催動。</p><p>📎 來源：<a href="https://news.cnyes.com/news/id/6469850" target="_blank" rel="noreferrer">鉅亨網</a>、<a href="https://www.prnewswire.com/news-releases/ficer-powering-digital-infrastructure-strengthening-communication-backbones-at-computex-taipei-2026-302774300.html" target="_blank" rel="noreferrer">PRNewswire</a>（TST 05:00）</p><hr><h2 id="📰-即時新聞-5條" tabindex="-1">📰 即時新聞（5條） <a class="header-anchor" href="#📰-即時新聞-5條" aria-label="Permalink to &quot;📰 即時新聞（5條）&quot;">​</a></h2><h3 id="_1-🔴-nvidia-computex-持續-rtx-spark-vera-rubin-40-億光子投資" tabindex="-1">1. 🔴 NVIDIA Computex 持續：RTX Spark + Vera Rubin + $40 億光子投資 <a class="header-anchor" href="#_1-🔴-nvidia-computex-持續-rtx-spark-vera-rubin-40-億光子投資" aria-label="Permalink to &quot;1. 🔴 NVIDIA Computex 持續：RTX Spark + Vera Rubin + $40 億光子投資&quot;">​</a></h3><p>黃仁勳 GTC Taipei 發表首款 Windows PC 晶片 RTX Spark、Vera Rubin 架構、$40 億光子投資（Coherent + Lumentum 各 $20 億）、Spectrum-X 409.6 Tb/s 2026H2 上市。COMPUTEX 6/2-5 台北舉行。（來源：NVIDIA、SiliconAngle，TST 05:00）</p><h3 id="_2-🔴-anthropic-秘密提交-ipo-估值-9-650-億超越-openai" tabindex="-1">2. 🔴 Anthropic 秘密提交 IPO，估值 $9,650 億超越 OpenAI <a class="header-anchor" href="#_2-🔴-anthropic-秘密提交-ipo-估值-9-650-億超越-openai" aria-label="Permalink to &quot;2. 🔴 Anthropic 秘密提交 IPO，估值 $9,650 億超越 OpenAI&quot;">​</a></h3><p>Anthropic 6/1 正式向 SEC 秘密提交 IPO 文件。此前融資 $650 億，估值 $9,650 億。AI 產業 IPO 熱潮正式啟動，CSP 資本支出預期進一步上升。（來源：Guardian、Forbes，TST 05:00）</p><h3 id="_3-🟡-broadcom-盤後財報-ai-收入-107-億預估-cpo-edge-ai-亮點" tabindex="-1">3. 🟡 Broadcom 盤後財報：AI 收入 $107 億預估，CPO + Edge AI 亮點 <a class="header-anchor" href="#_3-🟡-broadcom-盤後財報-ai-收入-107-億預估-cpo-edge-ai-亮點" aria-label="Permalink to &quot;3. 🟡 Broadcom 盤後財報：AI 收入 $107 億預估，CPO + Edge AI 亮點&quot;">​</a></h3><p>Broadcom 6/3 盤後公布 Q2 FY2026 財報，AI 收入預估 $107 億（+140% YoY）。COMPUTEX 展示 50G PON + Wi-Fi 8 + 5G FWA。管理層預測 FY2027 AI 晶片收入超 $1,000 億。（來源：Broadcom IR、SeekingAlpha，TST 05:00）</p><h3 id="_4-🟡-光纖供應短缺持續至-2027-ai-數據中心-國防需求驅動" tabindex="-1">4. 🟡 光纖供應短缺持續至 2027：AI 數據中心 + 國防需求驅動 <a class="header-anchor" href="#_4-🟡-光纖供應短缺持續至-2027-ai-數據中心-國防需求驅動" aria-label="Permalink to &quot;4. 🟡 光纖供應短缺持續至 2027：AI 數據中心 + 國防需求驅動&quot;">​</a></h3><p>全球光纖市場面臨嚴重供應短缺，預計持續至 2027。主要驅動：AI 數據中心擴張 + 國防光纖消費增加。光收發模組出貨量預計 2026 年 tripling。美廠 outsourcing to Southeast Asia → 台灣廠商受惠。（來源：GL-FiberCable、HengtongGlobal、TrendForce，TST 05:00）</p><h3 id="_5-🟡-authenx-computex-展示可拆卸-2d-fau-技術" tabindex="-1">5. 🟡 AuthenX COMPUTEX 展示可拆卸 2D FAU 技術 <a class="header-anchor" href="#_5-🟡-authenx-computex-展示可拆卸-2d-fau-技術" aria-label="Permalink to &quot;5. 🟡 AuthenX COMPUTEX 展示可拆卸 2D FAU 技術&quot;">​</a></h3><p>AuthenX 將展示可拆卸 2D 光纖陣列單元（FAU）技術，整合 12 吋 CMOS 超透鏡，解決光學封裝瓶頸，支援 3.2T 至 12.8T CPO 架構。（來源：PRNewswire、TST 05:00）</p><hr><h2 id="📊-產業趨勢摘要" tabindex="-1">📊 產業趨勢摘要 <a class="header-anchor" href="#📊-產業趨勢摘要" aria-label="Permalink to &quot;📊 產業趨勢摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>趨勢</th><th>狀態</th><th>說明</th></tr></thead><tbody><tr><td>銅退光進</td><td>🟢 加速</td><td>NVIDIA $40 億光子投資 + Spectrum-X 2026H2 上市</td></tr><tr><td>2026 商轉元年</td><td>🟢 進行中</td><td>CPO 小規模試產，2027+ 真正爆發</td></tr><tr><td>OCI-MSA 標準</td><td>🟡 推進中</td><td>行業標準制定持續</td></tr><tr><td>AI capex 擴張</td><td>🟢 強勁</td><td>Anthropic IPO + SoftBank +14% + Kospi +109% YTD</td></tr><tr><td>光纖供應短缺</td><td>🔴 持續至 2027</td><td>AI 數據中心 + 國防需求</td></tr><tr><td>COMPUTEX 2026</td><td>🔴 本週</td><td>6/2-5 台北，NVIDIA 核心角色</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>來源</th><th>查詢時間</th><th>內容</th></tr></thead><tbody><tr><td>1</td><td>NVIDIA 官網</td><td>TST 05:00</td><td>Computex GTC Taipei 發表</td></tr><tr><td>2</td><td>SiliconAngle</td><td>TST 05:00</td><td>Vera Rubin 量產</td></tr><tr><td>3</td><td>PCMag</td><td>TST 05:00</td><td>Computex 現場報導</td></tr><tr><td>4</td><td>Broadcom IR</td><td>TST 05:00</td><td>Q2 FY2026 財報資訊</td></tr><tr><td>5</td><td>SeekingAlpha</td><td>TST 05:00</td><td>Broadcom Q2 預覽</td></tr><tr><td>6</td><td>FuturumGroup</td><td>TST 05:00</td><td>Broadcom Edge AI 展示</td></tr><tr><td>7</td><td>鉅亨網</td><td>TST 05:00</td><td>台積電 + 台股</td></tr><tr><td>8</td><td>Guardian</td><td>TST 05:00</td><td>Anthropic IPO</td></tr><tr><td>9</td><td>Siemens Blog</td><td>TST 05:00</td><td>CPO 五大趨勢</td></tr><tr><td>10</td><td>GL-FiberCable</td><td>TST 05:00</td><td>光纖供應短缺</td></tr><tr><td>11</td><td>PRNewswire</td><td>TST 05:00</td><td>FICER + AuthenX COMPUTEX</td></tr><tr><td>12</td><td>FocusTaiwan</td><td>TST 05:00</td><td>台股 TAIEX 歷史新高</td></tr></tbody></table><hr><p><em>報告生成時間：2026-06-03 05:00 TST</em><em>下一份報告預計：2026-06-04 05:00 TST</em></p>',52)])])}const u=r(d,[["render",i]]);export{g as __pageData,u as default};
